INSERT INTO public.cultural_state_items (
  hub_id,
  item_name,
  short_description,
  about_state_tradition,
  history,
  cultural_significance,
  practice_and_pedagogy,
  performance_context,
  notable_exponents,
  discussion_site_id,
  cover_image_url,
  gallery_urls,
  sort_order,
  is_published
)
SELECT
  h.id,
  i.item_name,
  i.short_description,
  i.about_state_tradition,
  i.history,
  i.cultural_significance,
  i.practice_and_pedagogy,
  i.performance_context,
  i.notable_exponents,
  (
    substr(md5(concat(i.category, '|', i.state_code, '|', i.item_name)), 1, 8) || '-' ||
    substr(md5(concat(i.category, '|', i.state_code, '|', i.item_name)), 9, 4) || '-' ||
    substr(md5(concat(i.category, '|', i.state_code, '|', i.item_name)), 13, 4) || '-' ||
    substr(md5(concat(i.category, '|', i.state_code, '|', i.item_name)), 17, 4) || '-' ||
    substr(md5(concat(i.category, '|', i.state_code, '|', i.item_name)), 21, 12)
  )::uuid,
  concat(
    'https://xmbygaeixvzlyhbtkbnp.supabase.co/storage/v1/object/public/cultural-state/',
    i.category,
    '/',
    lower(replace(i.state_code, 'IN-', '')),
    '/cover.jpg'
  ),
  ARRAY[
    concat(
      'https://xmbygaeixvzlyhbtkbnp.supabase.co/storage/v1/object/public/cultural-state/',
      i.category,
      '/',
      lower(replace(i.state_code, 'IN-', '')),
      '/gallery/1.jpg'
    )
  ]::text[],
  i.sort_order,
  TRUE
FROM item_seed i
JOIN public.cultural_state_hubs h
  ON h.category = i.category
 AND h.state_code = i.state_code
ON CONFLICT (discussion_site_id) DO UPDATE SET
  item_name = EXCLUDED.item_name,
  short_description = EXCLUDED.short_description,
  about_state_tradition = EXCLUDED.about_state_tradition,
  history = EXCLUDED.history,
  cultural_significance = EXCLUDED.cultural_significance,
  practice_and_pedagogy = EXCLUDED.practice_and_pedagogy,
  performance_context = EXCLUDED.performance_context,
  notable_exponents = EXCLUDED.notable_exponents,
  cover_image_url = EXCLUDED.cover_image_url,
  gallery_urls = EXCLUDED.gallery_urls,
  sort_order = EXCLUDED.sort_order,
  is_published = EXCLUDED.is_published;

